document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll("[data-apod-video]").forEach(e=>{const t=e.querySelector("[data-apod-video-load]"),d=e.querySelector(".apod-video-poster"),o=e.querySelector(".apod-video-frame"),r=o?o.querySelector("iframe[data-src]"):null;t&&d&&o&&r&&t.addEventListener("click",()=>{const n=r.dataset.src;n&&(r.getAttribute("src")||r.setAttribute("src",n),d.hidden=!0,o.hidden=!1,e.classList.add("is-playing"),t.setAttribute("aria-expanded","true"),o.focus())})})});
